import{_ as t,c as e,o as i,V as l}from"./chunks/framework.9b555ede.js";const g=JSON.parse('{"title":"关于设计模式的思考","description":"主要记录下比较有意思的设计模式，以实用为主，结合使用场景，让人更容易接受","frontmatter":{"title":"关于设计模式的思考","author":"nkxrb","avatar":"http://cdnblog.nkxrb.xyz/images/home/avatar.png","authorLink":"blog.nkxrb.xyz","authorAbout":"nkxrb","authorDesc":"nkxrb","photos":"http://cdnblog.nkxrb.xyz/images/archives/desiner.jpg","categories":"serve","tags":["design"],"date":"2017-05-23T21:16:01.000Z","comments":true,"keywords":null,"description":"主要记录下比较有意思的设计模式，以实用为主，结合使用场景，让人更容易接受"},"headers":[],"relativePath":"original/【设计】关于设计模式的思考.md","filePath":"original/【设计】关于设计模式的思考.md","lastUpdated":1640536454000}'),a={name:"original/【设计】关于设计模式的思考.md"},r=l('<blockquote><p>千万，千万，不要被所谓的设计模式给框死了!!! 在我看来，设计模式相当于学术向的东西，而我们程序员实际开发中，设计模式不会按部就班的套用的。</p></blockquote><p>一个比较形象的比喻：设计模式就像武功秘籍，而当你真正面对敌人时，不会按照武功秘籍全套演一遍给人看吧，真想打败敌人，还要靠多本秘籍的不同排列组合才行，见招拆招才是王道！</p><p>只有将多个设计模式融会贯通，活学活用，才能走上高端程序员的道路。</p><p>注意遵守这几个重要的原则，代码质量将有质的飞跃</p><ul><li>开闭原则（抽象约束、封装变化）</li><li>里氏替换原则（可以扩展，重写，但不能改变原有的东西）</li><li>依赖倒置原则（每个类尽量提供接口或抽象类）</li><li>单一职责原则（全局单一性原则）</li><li>接口隔离原则（拆分成多个小接口，降低类对接口的依赖性）</li><li>迪米特法则（类似于中介）</li><li>合成复用原则（将已有的对象纳入新对象中，作为新对象的成员对象来实现）</li></ul><p>列一些比较常用的设计模式</p><ul><li>单例（太简单，单不要轻易使用，注意并发，加锁的性能）</li><li>工厂模式（提前生产以便不时之需）</li><li>适配器模式（处理通用业务的神器）</li><li>代理模式（一般用于框架搭建，架构师常用） ...</li></ul><p>下面介绍下比较经典的设计模式，以及可能使用的场景。</p><ul><li><a href="http://c.biancheng.net/view/1366.html" target="_blank" rel="noreferrer">这里将设计模式说得不能再明白了</a></li></ul>',9),o=[r];function n(_,s,p,c,d,u){return i(),e("div",null,o)}const m=t(a,[["render",n]]);export{g as __pageData,m as default};
